// src/components/About.jsx
import { useState } from 'react';
import ParticlesBg from './ParticlesBg';
import { useMediaQuery } from '../hooks/useMediaQuery';

export default function About() {
  const [hovered, setHovered] = useState(null);
  const isMobile = useMediaQuery('(max-width: 850px)');

  return (
    <section id="about" style={{ ...s.section, padding: isMobile ? '80px 20px' : '110px 5%' }}>

      {/* ── Fondo Premium (Glow + Grid + Partículas) ── */}
      <div style={s.bgGlow} />
      <div style={s.bgGrid} />
      <ParticlesBg opacity={0.35} />

      <div style={s.inner}>

        {/* ── Header ── */}
        <div style={s.header}>
          <p style={s.label}><span style={s.labelLine} />Sobre mí</p>
          <h2 style={s.title}>Mi <em style={s.titleEm}>historia</em></h2>
          <p style={s.sub}>De la logística y la atención al cliente al desarrollo de software.</p>
        </div>

        {/* ── Layout (Flex dinámico para responsive) ── */}
        <div style={{ display: 'flex', flexDirection: isMobile ? 'column' : 'row', gap: isMobile ? 40 : 80, alignItems: 'start' }}>

          {/* ── Columna izquierda (Bio Personal) ── */}
          <div style={{ width: isMobile ? '100%' : '380px', flexShrink: 0 }}>
            <p style={s.bioPara}>
              Si miras mi currículum verás que mi camino no ha sido el tradicional. Durante varios años trabajé en logística, tiendas de alto volumen y atención al cliente. Ahí aprendí cosas que no se enseñan en un tutorial: <strong style={s.strong}>disciplina, trabajo en equipo bajo presión y cómo tratar con las personas</strong>.
            </p>
            <p style={s.bioPara}>
              Hace un tiempo decidí dar un giro a mi vida y estudiar Desarrollo de Aplicaciones Web. Esa misma ética de trabajo me llevó a conseguir mi primera oportunidad en <strong style={s.strong}>Mercanza</strong>, donde tuve que salir de mi zona de confort y enfrentarme a código real en producción desde el primer día.
            </p>
            <p style={s.bioPara}>
              Hoy busco mi primera gran oportunidad como Full Stack. Sé que tengo mucho que aprender, pero te aseguro que <strong style={s.strong}>no me rindo ante un bug, asumo responsabilidades y valoro enormemente la oportunidad de crecer en un buen equipo</strong>.
            </p>

            <div style={s.infoList}>
              {[
                { label: 'Ubicación', val: 'Madrid' },
                { label: 'Email',     val: 'ruben14marco@gmail.com', href: 'mailto:ruben14marco@gmail.com' },
                { label: 'LinkedIn',  val: 'rubén-marco',            href: 'https://www.linkedin.com/in/rubén-marco-aa992b234' },
                { label: 'Perfil',    val: 'Proactivo, fiable, adaptable' },
              ].map(item => (
                <div key={item.label} style={s.infoItem}>
                  <span style={s.infoLbl}>{item.label}</span>
                  {item.href ? (
                    <a href={item.href} target="_blank" rel="noreferrer" style={s.infoLink}>{item.val}</a>
                  ) : (
                    <span style={s.infoVal}>{item.val}</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* ── Columna Derecha (Tarjetas de Valores) ── */}
          <div style={{ flex: 1, display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: 12 }}>

            {/* Tarjeta 1 */}
            <div style={{ ...s.card, ...(hovered === 0 ? s.cardHover : {}) }}
                 onMouseEnter={() => setHovered(0)} onMouseLeave={() => setHovered(null)}>
              <div style={s.cardIcon}>🚀</div>
              <div style={s.cardTitle}>Curva de aprendizaje acelerada</div>
              <p style={s.cardText}>En mi última experiencia tuve que dominar React y .NET en tiempo récord. Si no sé algo, lo investigo, lo practico y lo aprendo. Sin excusas.</p>
            </div>

            {/* Tarjeta 2 */}
            <div style={{ ...s.card, ...(hovered === 1 ? s.cardHover : {}) }}
                 onMouseEnter={() => setHovered(1)} onMouseLeave={() => setHovered(null)}>
              <div style={s.cardIcon}>🤝</div>
              <div style={s.cardTitle}>Cero ego, mucho equipo</div>
              <p style={s.cardText}>Vengo de trabajos donde si uno falla, la cadena se rompe. Sé escuchar, pedir ayuda a tiempo cuando me atasco y aceptar feedback para mejorar.</p>
            </div>

            {/* Tarjeta 3 (Ancho completo) */}
            <div style={{ ...s.card, gridColumn: isMobile ? 'span 1' : 'span 2', ...(hovered === 2 ? s.cardHover : {}) }}
                 onMouseEnter={() => setHovered(2)} onMouseLeave={() => setHovered(null)}>
              <div style={{ display: 'flex', gap: 20, alignItems: isMobile ? 'flex-start' : 'center', flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={{ fontSize: 48, lineHeight: 1 }}>⏱️</div>
                <div>
                  <div style={s.cardTitle}>Fiabilidad y compromiso</div>
                  <p style={s.cardText}>Estuve casi 3 años ininterrumpidos en mi anterior sector. Sé lo que significa comprometerse con un proyecto. Ahora busco un equipo de desarrollo donde echar raíces, aportar valor y sumar a largo plazo.</p>
                </div>
              </div>
            </div>

            {/* Tarjeta 4 (Ancho completo) */}
            <div style={{ ...s.card, ...s.c4, gridColumn: isMobile ? 'span 1' : 'span 2', ...(hovered === 3 ? s.c4Hover : {}) }}
                 onMouseEnter={() => setHovered(3)} onMouseLeave={() => setHovered(null)}>
              <div style={{ ...s.c4Quote, color: hovered === 3 ? 'rgba(232,58,58,0.5)' : 'rgba(232,58,58,0.22)' }}>"</div>
              <div>
                <p style={s.c4Text}>El código limpio y escalable es importante, pero mi objetivo final siempre es que el producto resuelva problemas reales del negocio.</p>
                <span style={s.c4Badge}><span style={s.c4BadgeDot} />Mentalidad de producto</span>
              </div>
            </div>

          </div>
        </div>
      </div>
    </section>
  );
}

